import type { Metadata } from 'next'
import Image from 'next/image'
import {
  ArrowRight,
  BadgeCheck,
  Brain,
  CalendarDays,
  Check,
  HeartPulse,
  MessageSquare,
  ScanSearch,
  ShieldCheck,
  Sparkles,
  UserRoundCheck,
} from 'lucide-react'
import { PremiumButton } from '@/components/ui/premium-button'
import { PremiumCard } from '@/components/ui/premium-card'
import { BeforeAfterGallery } from '@/components/implant/BeforeAfterGallery'
import { ConsultationCtaSection } from '@/components/implant/ConsultationCtaSection'
import { DigitalDentistrySection } from '@/components/implant/DigitalDentistrySection'
import { ImplantSystemsSection } from '@/components/implant/ImplantSystemsSection'
import { PatientStoriesSection } from '@/components/implant/PatientStoriesSection'

const pageTitle = 'Dental Implants | The British Dental Hub'
const pageDescription =
  'Restore your smile with premium implant dentistry using digital planning, world-class implant systems and meticulous clinical precision in Cairo.'

export const metadata: Metadata = {
  title: pageTitle,
  description: pageDescription,
  keywords: [
    'Dental Implants',
    'Premium Implant Dentistry',
    'Dental Implants Egypt',
    'Smile Restoration',
    'Digital Dental Planning',
    'British Dental Clinic',
    'Cosmetic Dentistry',
  ],
  alternates: {
    canonical: '/dental-implants',
  },
  openGraph: {
    title: pageTitle,
    description: pageDescription,
    url: '/dental-implants',
    type: 'website',
    siteName: 'The British Dental Hub',
    images: [
      {
        url: '/images/hero-clinic.png',
        width: 1200,
        height: 630,
        alt: 'Premium dental implant treatment at The British Dental Hub',
      },
    ],
  },
  twitter: {
    card: 'summary_large_image',
    title: pageTitle,
    description: pageDescription,
    images: ['/images/hero-clinic.png'],
  },
}

const trustPoints = [
  'British Standards',
  'Digital Planning',
  'Premium Implant Systems',
  'Personalized Care',
]

const reasons = [
  {
    number: '01',
    icon: ScanSearch,
    title: 'Digital Treatment Planning',
    description:
      'Every implant is digitally planned using advanced 3D CBCT imaging for maximum precision and predictable long-term results.',
  },
  {
    number: '02',
    icon: ShieldCheck,
    title: 'Premium Implant Systems',
    description:
      'We use internationally recognized implant systems supported by long-term scientific evidence and exceptional reliability.',
  },
  {
    number: '03',
    icon: UserRoundCheck,
    title: 'Experienced Implant Team',
    description:
      'Treatment is performed by experienced dentists following modern British clinical protocols and meticulous planning.',
  },
  {
    number: '04',
    icon: HeartPulse,
    title: 'Comfortable Surgery',
    description:
      'Gentle surgical techniques and modern anesthesia provide a comfortable and stress-free treatment experience.',
  },
  {
    number: '05',
    icon: Sparkles,
    title: 'Natural Aesthetic Results',
    description:
      'Every implant restoration is carefully crafted to match your smile naturally in shape, color, and function.',
  },
  {
    number: '06',
    icon: BadgeCheck,
    title: 'Long-Term Support',
    description:
      'Regular follow-up appointments help protect your investment and maintain healthy implants for many years.',
  },
]

const journeySteps = [
  {
    number: '01',
    icon: CalendarDays,
    title: 'Consultation',
    description: 'A thorough clinical assessment and treatment discussion to define the optimal implant pathway.',
    detail: 'Duration: 30–45 min',
  },
  {
    number: '02',
    icon: ScanSearch,
    title: '3D CBCT Scan',
    description: 'Advanced digital diagnosis and bone assessment for precise anatomical planning.',
    detail: 'Precision imaging',
  },
  {
    number: '03',
    icon: Brain,
    title: 'Digital Planning',
    description: 'Virtual implant positioning designed for maximum precision, stability and long-term harmony.',
    detail: 'Custom treatment design',
  },
  {
    number: '04',
    icon: ShieldCheck,
    title: 'Implant Placement',
    description: 'Precise implant placement using minimally invasive techniques for maximum comfort and predictability.',
    detail: 'Gentle and efficient',
  },
  {
    number: '05',
    icon: HeartPulse,
    title: 'Healing Phase',
    description: 'A carefully guided osseointegration period with attentive follow-up and recovery support.',
    detail: 'Supportive recovery',
  },
  {
    number: '06',
    icon: Sparkles,
    title: 'Final Restoration',
    description: 'A bespoke crown crafted to restore natural form, function and confidence with exceptional aesthetics.',
    detail: 'Beautiful long-term result',
  },
]

export default function DentalImplantsPage() {
  return (
    <main className="min-h-screen bg-background">
      <section className="relative isolate overflow-hidden bg-[#07152C]">
        <div className="absolute inset-0">
          <Image
            src="/images/hero-clinic.png"
            alt="Luxury dental clinic interior at The British Dental Hub"
            fill
            priority
            sizes="100vw"
            className="object-cover opacity-30"
          />
          <div className="absolute inset-0 bg-[linear-gradient(90deg,rgba(7,21,44,0.96)_0%,rgba(7,21,44,0.82)_45%,rgba(7,21,44,0.7)_100%)]" />
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_top_left,rgba(255,209,110,0.16),transparent_35%)]" />
        </div>

        <div className="relative mx-auto flex min-h-screen max-w-7xl items-center px-6 py-24 sm:px-8 lg:px-10 lg:py-32">
          <div className="max-w-3xl">
            <p className="eyebrow justify-start">
              <span className="h-px w-10 bg-primary" />
              Premium Implant Dentistry
            </p>

            <h1 className="section-title mt-6 max-w-3xl text-balance text-white sm:text-5xl lg:text-[4rem] leading-[0.95]">
              Dental Implants Inspired by British Standards
            </h1>

            <p className="mt-6 max-w-2xl text-lg font-light leading-8 text-slate-200/90 sm:text-xl sm:leading-9">
              Restore your smile with premium implant dentistry using digital planning, world-class implant systems and meticulous clinical precision in Cairo.
            </p>

            <div className="mt-10 flex flex-col gap-4 sm:flex-row sm:items-center">
              <PremiumButton
                href="/#contact"
                variant="primary"
                className="min-w-[220px]"
                iconRight={<ArrowRight className="size-4" />}
              >
                Book Consultation
              </PremiumButton>
              <PremiumButton
                href="https://wa.me/201556887765"
                variant="secondary"
                target="_blank"
                rel="noopener noreferrer"
                className="min-w-[240px]"
                iconLeft={<MessageSquare className="size-4" />}
              >
                WhatsApp Consultation
              </PremiumButton>
            </div>
          </div>
        </div>
      </section>

      <section className="relative overflow-hidden border-t border-white/10 bg-[#07152C]/95 py-24 sm:py-28 lg:py-32">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,rgba(255,209,110,0.08),transparent_60%)]" />

        <div className="relative mx-auto max-w-7xl px-6 sm:px-8 lg:px-10">
          <div className="mx-auto max-w-3xl text-center">
            <p className="eyebrow justify-center">
              <span className="h-px w-10 bg-primary" />
              Why Choose The British Dental Hub?
            </p>
            <h2 className="section-title mt-6 text-white">
              Why Choose The British Dental Hub?
            </h2>
            <p className="mt-6 text-lg font-light leading-8 text-slate-300/85 sm:text-xl">
              British-inspired precision, premium implant systems and meticulous patient care designed to deliver long-term confidence.
            </p>
          </div>

          <div className="mt-16 grid gap-6 md:grid-cols-2 xl:grid-cols-3">
            {reasons.map((reason, index) => {
              const Icon = reason.icon

              return (
                <PremiumCard
                  key={reason.title}
                  className="group h-full overflow-hidden rounded-[30px] border border-white/15 bg-[rgba(5,13,31,0.96)] p-8 shadow-[0_24px_80px_rgba(0,0,0,0.24)] backdrop-blur-sm"
                >
                  <div className="h-full">
                    <div className="flex items-start justify-between gap-4">
                      <div className="flex h-16 w-16 items-center justify-center rounded-[24px] border border-primary/20 bg-primary/10 text-primary transition duration-300 ease-out group-hover:scale-105 group-hover:border-primary/40 group-hover:bg-primary/15">
                        <Icon className="size-8" strokeWidth={1.6} />
                      </div>
                      <span className="text-sm font-semibold uppercase tracking-[0.3em] text-primary/80">
                        {reason.number}
                      </span>
                    </div>
                    <h3 className="mt-7 text-[1.3rem] font-semibold leading-tight text-white transition duration-300 ease-out group-hover:text-primary/95">
                      {reason.title}
                    </h3>
                    <p className="mt-4 text-sm font-light leading-7 text-slate-300/85">
                      {reason.description}
                    </p>
                    <div className="mt-8 flex items-center justify-between border-t border-white/10 pt-5">
                      <span className="text-[0.72rem] font-semibold uppercase tracking-[0.32em] text-slate-300/70">
                        Learn More
                      </span>
                      <div className="flex h-10 w-10 items-center justify-center rounded-full border border-primary/20 bg-white/5 text-primary transition duration-300 ease-out group-hover:translate-x-1 group-hover:border-primary/40 group-hover:bg-primary/10">
                        <ArrowRight className="size-4" />
                      </div>
                    </div>
                  </div>
                </PremiumCard>
              )
            })}
          </div>

          <div className="mt-14 flex flex-wrap items-center justify-center gap-3 rounded-[30px] border border-white/10 bg-white/5 p-4 backdrop-blur-sm sm:gap-4 sm:p-5">
            {trustPoints.map((point) => (
              <div
                key={point}
                className="inline-flex items-center gap-2 rounded-full border border-primary/20 bg-[#07152C]/80 px-4 py-2.5 text-[0.7rem] font-semibold uppercase tracking-[0.24em] text-primary transition duration-300 ease-out hover:-translate-y-0.5 hover:border-primary/40 hover:bg-[#081a36]"
              >
                <Check className="size-3.5" />
                <span>{point}</span>
              </div>
            ))}
          </div>
        </div>
      </section>

      <section className="relative overflow-hidden border-t border-white/10 bg-[#050d1f] py-24 sm:py-28 lg:py-32">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,rgba(255,209,110,0.06),transparent_70%)]" />

        <div className="relative mx-auto max-w-7xl px-6 sm:px-8 lg:px-10">
          <div className="mx-auto max-w-3xl text-center">
            <p className="eyebrow justify-center">
              <span className="h-px w-10 bg-primary" />
              Your Implant Journey
            </p>
            <h2 className="section-title mt-6 text-white">
              Your Implant Journey
            </h2>
            <p className="mt-6 text-lg font-light leading-8 text-slate-300/85 sm:text-xl">
              From your first consultation to your final smile, every step is carefully planned according to modern British implant protocols.
            </p>
          </div>

          <div className="mt-16 hidden lg:block">
            <div className="relative">
              <div className="absolute left-6 right-6 top-12 h-px origin-left bg-gradient-to-r from-primary/55 via-primary/80 to-primary/55 transition-opacity duration-1000 ease-out" />
              <div className="flex items-stretch gap-4">
                {journeySteps.map((step, index) => {
                  const Icon = step.icon
                  const isHighlighted = step.number === '04'

                  return (
                    <div key={step.title} className="relative flex-1 pt-10">
                      <div className={`absolute left-1/2 top-0 flex h-12 w-12 -translate-x-1/2 items-center justify-center rounded-full border bg-[#07152C] text-primary shadow-[0_0_0_8px_rgba(255,209,110,0.08)] transition duration-500 ease-out ${isHighlighted ? 'border-primary/60 shadow-[0_0_0_10px_rgba(255,209,110,0.18)]' : 'border-primary/30'}`}>
                        <span className="text-[0.7rem] font-semibold uppercase tracking-[0.24em]">
                          {step.number}
                        </span>
                      </div>
                      <div className="absolute left-1/2 top-12 h-10 w-px -translate-x-1/2 bg-gradient-to-b from-primary/70 to-transparent" />
                      <PremiumCard className={`group h-full rounded-[30px] border bg-[rgba(7,21,44,0.95)] p-7 shadow-[0_24px_80px_rgba(0,0,0,0.22)] backdrop-blur-sm transition duration-300 ease-out hover:-translate-y-2 hover:border-primary/45 hover:shadow-[0_24px_80px_rgba(255,209,110,0.12)] lg:hover:shadow-[0_24px_90px_rgba(255,209,110,0.16)] ${isHighlighted ? 'border-primary/45 shadow-[0_24px_80px_rgba(255,209,110,0.12)]' : 'border-white/15'}`}>
                        <div className="h-full opacity-0 translate-y-6 animate-about-fade-scale" style={{ animationDelay: `${index * 120}ms` }}>
                          <div className="flex h-14 w-14 items-center justify-center rounded-[24px] border border-primary/20 bg-primary/10 text-primary transition duration-300 ease-out group-hover:scale-105 group-hover:border-primary/40 group-hover:bg-primary/15">
                            <Icon className="size-7" strokeWidth={1.6} />
                          </div>
                          <h3 className={`mt-6 text-[1.15rem] font-semibold leading-tight transition duration-300 ease-out ${isHighlighted ? 'text-primary/95' : 'text-white group-hover:text-primary/95'}`}>
                            {step.title}
                          </h3>
                          <p className="mt-3 text-sm font-light leading-7 text-slate-300/85">
                            {step.description}
                          </p>
                          <p className="mt-4 text-[0.72rem] font-semibold uppercase tracking-[0.28em] text-primary/75">
                            {step.detail}
                          </p>
                        </div>
                      </PremiumCard>
                    </div>
                  )
                })}
              </div>
            </div>
          </div>

          <div className="relative mt-8 space-y-4 lg:hidden">
            <div className="absolute left-6 top-2 bottom-2 w-px bg-gradient-to-b from-primary/70 via-primary/40 to-transparent" />
            {journeySteps.map((step, index) => {
              const Icon = step.icon
              const isHighlighted = step.number === '04'

              return (
                <div key={step.title} className="relative pl-14">
                  <div className={`absolute left-0 top-6 flex h-12 w-12 items-center justify-center rounded-full border bg-[#07152C] text-primary shadow-[0_0_0_8px_rgba(255,209,110,0.08)] transition duration-500 ease-out ${isHighlighted ? 'border-primary/60 shadow-[0_0_0_10px_rgba(255,209,110,0.18)]' : 'border-primary/30'}`}>
                    <span className="text-[0.7rem] font-semibold uppercase tracking-[0.24em]">
                      {step.number}
                    </span>
                  </div>
                  <PremiumCard className={`group rounded-[30px] border bg-[rgba(7,21,44,0.95)] p-7 shadow-[0_24px_80px_rgba(0,0,0,0.22)] backdrop-blur-sm transition duration-300 ease-out hover:-translate-y-2 hover:border-primary/45 hover:shadow-[0_24px_80px_rgba(255,209,110,0.12)] ${isHighlighted ? 'border-primary/45 shadow-[0_24px_80px_rgba(255,209,110,0.12)]' : 'border-white/15'}`}>
                    <div className="opacity-0 translate-y-6 animate-about-fade-scale" style={{ animationDelay: `${index * 120}ms` }}>
                      <div className="flex h-14 w-14 items-center justify-center rounded-[24px] border border-primary/20 bg-primary/10 text-primary transition duration-300 ease-out group-hover:scale-105 group-hover:border-primary/40 group-hover:bg-primary/15">
                        <Icon className="size-7" strokeWidth={1.6} />
                      </div>
                      <h3 className={`mt-6 text-[1.15rem] font-semibold leading-tight transition duration-300 ease-out ${isHighlighted ? 'text-primary/95' : 'text-white group-hover:text-primary/95'}`}>
                        {step.title}
                      </h3>
                      <p className="mt-3 text-sm font-light leading-7 text-slate-300/85">
                        {step.description}
                      </p>
                      <p className="mt-4 text-[0.72rem] font-semibold uppercase tracking-[0.28em] text-primary/75">
                        {step.detail}
                      </p>
                    </div>
                  </PremiumCard>
                </div>
              )
            })}
          </div>

          <div className="mt-14 flex flex-col items-center justify-center gap-3 text-center">
            <p className="text-sm font-medium uppercase tracking-[0.3em] text-primary/80">
              Ready to begin your implant journey?
            </p>
            <PremiumButton href="/#contact" variant="secondary" className="min-w-[220px]">
              Book Consultation
            </PremiumButton>
          </div>
        </div>
      </section>

      <BeforeAfterGallery />
      <ImplantSystemsSection />
      <DigitalDentistrySection />
      <PatientStoriesSection />
      <ConsultationCtaSection />
    </main>
  )
}
